// hooks/useTourFilters.js
import { useState, useCallback } from 'react';

export function useTourFilters() {
  const [adults, setAdults] = useState(2);
  const [selectedChildren, setSelectedChildren] = useState([]);
  const [dateSelection, setDateSelection] = useState([]);
  const [nightSelection, setNightSelection] = useState([]);
  const [currentMonthIdx, setCurrentMonthIdx] = useState(0);

  const monthsData = [
    { name: 'Февраль', short: 'фев', days: Array.from({length: 28}, (_, i) => i + 1) },
    { name: 'Март', short: 'мар', days: Array.from({length: 31}, (_, i) => i + 1) }
  ];

  const updateAdults = useCallback((val) => {
    setAdults(prev => Math.max(1, prev + val));
  }, []);

  const addChild = useCallback((age) => {
    setSelectedChildren(prev => [...prev, age]);
  }, []);

  const removeChild = useCallback((index) => {
    setSelectedChildren(prev => prev.filter((_, i) => i !== index));
  }, []);

  const selectDate = useCallback((day, monthShort) => {
    setDateSelection(prev => {
      const newSel = [...prev, { day, month: monthShort }];
      return newSel.length > 2 ? newSel.slice(-2) : newSel;
    });
  }, []);

  const selectNights = useCallback((night) => {
    setNightSelection(prev => {
      const newSel = [...prev, night].sort((a,b) => a-b);
      return newSel.length > 2 ? newSel.slice(-2) : newSel;
    });
  }, []);

  return {
    adults, selectedChildren, dateSelection, nightSelection, currentMonthIdx,
    monthsData, setCurrentMonthIdx, updateAdults, addChild, removeChild,
    selectDate, selectNights
  };
}
